import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;

try {
  log.info("===== Workflow Start =====");

  workflowStartTime = new Date();
  requestId = UUID.randomUUID().toString();
  isSuccess = false;
  errorMessage = null;

  log.info("RequestID: " + requestId);
  log.info("ApplicationName: " + applicationName);
  log.info("GroupName: " + groupName);

} catch (Exception e) {
  log.error("Init error: " + e.getMessage());
  errorMessage = "Initialization error: " + e.getMessage();
  isSuccess = false;
}

import sailpoint.object.*;
import java.util.*;

try {
  log.info("Validating input parameters");

  List errors = new ArrayList();

  if (applicationName == null || applicationName.trim().length() == 0) {
    errors.add("applicationName");
  }
  if (groupName == null || groupName.trim().length() == 0) {
    errors.add("groupName");
  }
  if (groupDescription == null || groupDescription.trim().length() == 0) {
    errors.add("groupDescription");
  }
  if (groupOwner == null || groupOwner.trim().length() == 0) {
    errors.add("groupOwner");
  }
  if (groupType == null || groupType.trim().length() == 0) {
    errors.add("groupType");
  }
  if (groupScope == null || groupScope.trim().length() == 0) {
    errors.add("groupScope");
  }
  if (organizationalUnit == null || organizationalUnit.trim().length() == 0) {
    errors.add("organizationalUnit");
  }

  if (errors.size() > 0) {
    errorMessage = "Missing required parameters: " + errors.toString();
    isSuccess = false;
    log.error(errorMessage);
  } else {
    log.info("Validation passed");
    isSuccess = true;
  }

} catch (Exception e) {
  log.error("Validation error: " + e.getMessage());
  errorMessage = "Validation error: " + e.getMessage();
  isSuccess = false;
}

import sailpoint.object.*;

try {
  log.info("Getting AD application: " + applicationName);

  adApplication = context.getObjectByName(sailpoint.object.Application.class, applicationName);

  if (adApplication == null) {
    errorMessage = "Application not found: " + applicationName;
    isSuccess = false;
    log.error(errorMessage);
  } else {
    log.info("Application found");
    isSuccess = true;
  }

} catch (Exception e) {
  log.error("GetADApplication error: " + e.getMessage());
  errorMessage = "Error getting application: " + e.getMessage();
  isSuccess = false;
}

import sailpoint.object.*;
import java.util.*;

try {
  log.info("Building provisioning plan");

  ProvisioningPlan plan = new ProvisioningPlan();
  ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest(
    ProvisioningPlan.AccountRequest.Type.Create, applicationName, null, null);

  Map attributes = new HashMap();
  attributes.put("sAMAccountName", groupName);
  attributes.put("cn", groupName);
  attributes.put("displayName", groupName);
  attributes.put("description", groupDescription);
  attributes.put("groupType", groupType);
  attributes.put("groupScope", groupScope);
  attributes.put("ou", organizationalUnit);
  attributes.put("managedBy", groupOwner);

  if (groupEmail != null && groupEmail.trim().length() > 0) {
    attributes.put("mail", groupEmail);
    log.info("Added email: " + groupEmail);
  }

  if (additionalAttributes != null && additionalAttributes.size() > 0) {
    attributes.putAll(additionalAttributes);
    log.info("Added " + additionalAttributes.size() + " custom attributes");
  }

  for (String attrName : attributes.keySet()) {
    Object val = attributes.get(attrName);
    if (val != null) {
      acctReq.add(new ProvisioningPlan.AttributeRequest(attrName, 
        ProvisioningPlan.Operation.Set, val));
    }
  }

  plan.add(acctReq);
  workflow.put("provisioningPlan", plan);

  log.info("Plan built with " + attributes.size() + " attributes");
  isSuccess = true;

} catch (Exception e) {
  log.error("BuildPlan error: " + e.getMessage());
  errorMessage = "Error building plan: " + e.getMessage();
  isSuccess = false;
}

import sailpoint.object.*;

try {
  log.info("Executing provisioning plan");

  ProvisioningPlan plan = (ProvisioningPlan) workflow.get("provisioningPlan");

  if (plan == null) {
    errorMessage = "Provisioning plan not found";
    isSuccess = false;
    log.error(errorMessage);
    return;
  }

  if (adApplication == null) {
    errorMessage = "AD Application is null";
    isSuccess = false;
    log.error(errorMessage);
    return;
  }

  sailpoint.connector.Connector connector = adApplication.getConnector();

  if (connector == null) {
    errorMessage = "Connector not found for application";
    isSuccess = false;
    log.error(errorMessage);
    return;
  }

  connector.provision(context, adApplication, plan);
  log.info("Provisioning executed successfully");
  isSuccess = true;

} catch (Exception e) {
  log.error("ExecutePlan error: " + e.getMessage());
  errorMessage = "Error executing plan: " + e.getMessage();
  isSuccess = false;
}

import sailpoint.object.*;
import java.util.*;

try {
  log.info("Logging success");

  Date endTime = new Date();
  long duration = endTime.getTime() - workflowStartTime.getTime();

  AuditEvent event = new AuditEvent();
  event.setAction("CreateADGroup");
  event.setSource("Workflow");
  event.setInterface("API");
  event.setComment("SUCCESS: Group " + groupName + " created in " + duration + "ms");

  Map attrs = new HashMap();
  if (requestId != null) attrs.put("requestId", requestId);
  if (groupName != null) attrs.put("groupName", groupName);
  if (groupOwner != null) attrs.put("owner", groupOwner);
  attrs.put("duration", String.valueOf(duration));
  event.setAttributes(attrs);

  context.saveObject(event);
  context.commitTransaction();

  log.info("Success logged");

} catch (Exception e) {
  log.error("Logging error: " + e.getMessage());
}

import sailpoint.object.*;
import java.util.*;

try {
  log.info("Logging error");

  Date endTime = new Date();
  long duration = endTime.getTime() - workflowStartTime.getTime();

  AuditEvent event = new AuditEvent();
  event.setAction("CreateADGroup");
  event.setSource("Workflow");
  event.setInterface("API");

  String errorMsg = (errorMessage != null) ? errorMessage : "Unknown error";
  event.setComment("FAILED: " + errorMsg);

  Map attrs = new HashMap();
  if (requestId != null) attrs.put("requestId", requestId);
  if (groupName != null) attrs.put("groupName", groupName);
  attrs.put("error", errorMsg);
  attrs.put("duration", String.valueOf(duration));
  event.setAttributes(attrs);

  context.saveObject(event);
  context.commitTransaction();

  log.info("Error logged");

} catch (Exception e) {
  log.error("Error logging: " + e.getMessage());
}
